import "./CollapsedText.css";
import Accordion from 'react-bootstrap/Accordion';

function CollapsedText({name, text, buttonComponent, section}) {
  return (
    <Accordion>
      <Accordion.Item eventKey="0" id={section}>
        <Accordion.Header>{name}</Accordion.Header>
        <Accordion.Body>
         {text}
         {buttonComponent}
        </Accordion.Body>
      </Accordion.Item>
    </Accordion>
  );
}

export default CollapsedText;
